const firstItem = $input.first() || {};

const errorObj = firstItem.error || {};
const cause = errorObj.cause || {};

const jsonObj = firstItem.json || {};

const nestedError = jsonObj.error || {};
const nestedCause = nestedError.cause || {};

const pgCode = String(
  cause.code ||
  errorObj.code ||
  nestedCause.code ||
  nestedError.code ||
  jsonObj.code ||
  ''
);

const rawMessage = String(
  jsonObj.message ||
  cause.message ||
  errorObj.message ||
  errorObj.description ||
  nestedCause.message ||
  nestedError.message ||
  nestedError.description ||
  'Error desconocido'
);

let status = 500;
let errorType = 'Internal Server Error';
let message = rawMessage;
let code = 'DB_ERROR';

// Unique constraint violation
if (
  pgCode === '23505' ||
  rawMessage.includes('unique constraint')
) {
  status = 409;
  errorType = 'Conflict';
  code = 'DUPLICATE_ENTRY';

  if (rawMessage.toLowerCase().includes('email')) {
    message = 'El correo electrÃ³nico ya se encuentra registrado.';
    code = 'EMAIL_ALREADY_EXISTS';
  } else {
    const match = rawMessage.match(
      /unique constraint \"(.+?)\"/i
    );

    message = match
      ? `Ya existe un registro que viola la restricciÃ³n: ${match[1]}.`
      : 'Ya existe un registro con esos datos.';
  }
}

// NOT NULL violation
else if (
  pgCode === '23502' ||
  rawMessage.includes('not-null constraint') ||
  rawMessage.includes('violates not-null')
) {
  status = 422;
  errorType = 'Unprocessable Entity';
  code = 'MISSING_REQUIRED_FIELD';

  const match = rawMessage.match(/column \"(.+?)\"/);

  const field = match
    ? match[1]
    : 'desconocido';

  message = `El campo "${field}" es obligatorio y no puede estar vacÃ­o.`;
}

// Foreign key violation
else if (
  pgCode === '23503' ||
  rawMessage.includes('foreign key constraint')
) {
  status = 409;
  errorType = 'Conflict';
  code = 'FOREIGN_KEY_VIOLATION';

  message =
    'El registro referenciado no existe o ha sido eliminado.';
}

// Check constraint violation
else if (
  pgCode === '23514' ||
  rawMessage.includes('check constraint')
) {
  status = 422;
  errorType = 'Unprocessable Entity';
  code = 'CHECK_VIOLATION';

  message =
    'Los datos enviados no cumplen las restricciones requeridas.';
}

// Invalid date format
else if (
  rawMessage.includes('invalid input syntax for type date')
) {
  status = 422;
  errorType = 'Unprocessable Entity';
  code = 'INVALID_DATE_FORMAT';

  message =
    'El formato de fecha introducido no es vÃ¡lido o estÃ¡ vacÃ­o.';
}

// Generic invalid input
else if (
  rawMessage.includes('invalid input syntax')
) {
  status = 422;
  errorType = 'Unprocessable Entity';
  code = 'INVALID_INPUT_FORMAT';

  message =
    'Uno de los campos introducidos tiene un formato incorrecto (ej: texto en lugar de nÃºmero).';
}

return [
  {
    json: {
      status,
      error: errorType,
      message,
      code,
    },
  },
];

const body = $input.item.json.body || {};
const filters = body.filters || {};

const page = parseInt(body.page) || 1;
const pageSize = parseInt(body.pageSize) || 10;
const offset = (page - 1) * pageSize;

const params = [];
let paramIndex = 1;
let whereClause = 'WHERE 1=1';

if (
  filters.searchText &&
  typeof filters.searchText === 'string' &&
  filters.searchText.trim() !== ''
) {
  whereClause += `
    AND (
      f.curso ILIKE $${paramIndex}
      OR f.denominacion ILIKE $${paramIndex}
    )
  `;
  params.push(`%${filters.searchText}%`);
  paramIndex++;
}

if (
  filters.id_estado !== undefined &&
  filters.id_estado !== null &&
  filters.id_estado !== ''
) {
  whereClause += ` AND f.id_estado = $${paramIndex}`;
  params.push(filters.id_estado);
  paramIndex++;
}

if (
  filters.activo !== undefined &&
  filters.activo !== null &&
  filters.activo !== ''
) {
  whereClause += ` AND f.activo = $${paramIndex}`;
  params.push(filters.activo);
  paramIndex++;
}

// PaginaciÃ³n
params.push(pageSize);
const limitParam = paramIndex++;

params.push(offset);
const offsetParam = paramIndex++;

// Query principal
const query = `
WITH total_count AS (
  SELECT COUNT(DISTINCT f.id) AS total
  FROM formacion f
  ${whereClause}
),
global_counts AS (
  SELECT 
    COUNT(*) AS total_global,
    SUM(CASE WHEN activo = true THEN 1 ELSE 0 END) AS total_activos,
    SUM(CASE WHEN activo = false THEN 1 ELSE 0 END) AS total_inactivos
  FROM formacion
),
paginado AS (
  SELECT
    f.*,
    ef.nombre AS estado_nombre,
    af.nombre AS area_nombre,
    mf.nombre AS modalidad_nombre,
    exe.nombre AS ejecucion_nombre,
    COUNT(ft.id_trabajador) AS num_trabajadores
  FROM formacion f
  LEFT JOIN estado_formacion ef ON ef.id = f.id_estado
  LEFT JOIN area_formacion af ON af.id = f.id_area
  LEFT JOIN modalidad_formacion mf ON mf.id = f.id_modalidad
  LEFT JOIN ejecucion_formacion exe ON exe.id = f.id_ejecucion
  LEFT JOIN formacion_trabajador ft ON ft.id_formacion = f.id
  ${whereClause}
  GROUP BY 
    f.id,
    ef.nombre,
    af.nombre,
    mf.nombre,
    exe.nombre
  ORDER BY f.created_at DESC NULLS LAST
  LIMIT $${limitParam} OFFSET $${offsetParam}
)

SELECT 
  paginado.*,
  total_count.total AS total_records,
  global_counts.total_global,
  global_counts.total_activos,
  global_counts.total_inactivos
FROM paginado, total_count, global_counts;
`;

return [
  {
    json: {
      query,
      params,
      page,
      pageSize,
    },
  },
];

const body = $input.item.json.body || {};
const filters = body.filters || {};
const idFormacion = body.id_formacion;
const params = [];
let paramIndex = 1;

let query = `SELECT
  t.id,
  t.nombre,
  t.primer_apellido,
  t.segundo_apellido,
  t.dni_nif_pasaporte,
  t.email,
  t.telefono,
  t.activo,
  CASE WHEN ft.id IS NOT NULL THEN true ELSE false END as asignado
FROM trabajador t
LEFT JOIN formacion_trabajador ft
  ON ft.id_trabajador = t.id AND ft.id_formacion = $${paramIndex}
WHERE t.activo = true`;
params.push(idFormacion);
paramIndex++;

if (filters.searchText && typeof filters.searchText === 'string' && filters.searchText.trim() !== '') {
  query += ` AND (CONCAT(t.nombre, ' ', t.primer_apellido, ' ', COALESCE(t.segundo_apellido,'')) ILIKE $${paramIndex} OR t.dni_nif_pasaporte ILIKE $${paramIndex})`;
  params.push(`%${filters.searchText}%`);
  paramIndex++;
}

if (filters.soloDisponibles === true) {
  query += ' AND ft.id IS NULL';
}

query += ' ORDER BY t.primer_apellido, t.nombre';

return [{ json: { query, params } }];

